import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateInventoryInsight(stockData: any) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this inventory data and provide 3 brief professional insights for optimization: ${JSON.stringify(stockData)}`,
      config: {
        systemInstruction: "You are a professional inventory management consultant.",
        temperature: 0.7,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Unable to generate insights at this time.";
  }
}

import React, { useState, useEffect } from 'react';
import { StockItem, User } from './types';
import Login from './components/Login';
import Dashboard from './components/Dashboard';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [inventory, setInventory] = useState<StockItem[]>(() => {
    const saved = localStorage.getItem('omnistock_inventory');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('omnistock_inventory', JSON.stringify(inventory));
  }, [inventory]);

  const handleLogin = (userData: User) => {
    setUser(userData);
  };

  const handleLogout = () => {
    setUser(null);
    setIsAdmin(false);
  };

  const handleAddStock = (item: StockItem) => {
    setInventory(prev => [item, ...prev]);
  };

  const handleDeleteStock = (id: string) => {
    setInventory(prev => prev.filter(i => i.id !== id));
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <Dashboard 
      user={user} 
      inventory={inventory}
      isAdmin={isAdmin}
      setIsAdmin={setIsAdmin}
      onLogout={handleLogout}
      onAddStock={handleAddStock}
      onDeleteStock={handleDeleteStock}
    />
  );
};

export default App;

import React, { useState } from 'react';
import { User } from '../types';

interface LoginProps {
  onLogin: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isSignup, setIsSignup] = useState(false);
  const [name, setName] = useState('');
  const [contact, setContact] = useState('');
  const [email, setEmail] = useState('');
  const [loginPin, setLoginPin] = useState('');
  const [error, setError] = useState('');

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !contact || !email) {
      setError('Please fill all fields');
      return;
    }
    const newUser: User = { name, contact, email };
    const users = JSON.parse(localStorage.getItem('omnistock_users') || '[]');
    users.push(newUser);
    localStorage.setItem('omnistock_users', JSON.stringify(users));
    setError('Account created! Login with the last 6 digits of your contact.');
    setIsSignup(false);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users: User[] = JSON.parse(localStorage.getItem('omnistock_users') || '[]');
    const foundUser = users.find(u => {
      const pin = u.contact.slice(-6);
      return (u.email === email || u.name === name) && pin === loginPin;
    });

    if (foundUser) {
      onLogin(foundUser);
    } else {
      setError('Invalid credentials or PIN');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100">
        <div className="p-8 bg-indigo-600 text-white text-center">
          <h1 className="text-3xl font-bold">OmniStock</h1>
          <p className="text-indigo-100 mt-2">Professional Inventory Management</p>
        </div>

        <div className="p-8">
          <div className="flex mb-8 bg-slate-100 p-1 rounded-lg">
            <button 
              className={`flex-1 py-2 rounded-md transition ${!isSignup ? 'bg-white shadow-sm text-indigo-600 font-semibold' : 'text-slate-500'}`}
              onClick={() => setIsSignup(false)}
            >
              Login
            </button>
            <button 
              className={`flex-1 py-2 rounded-md transition ${isSignup ? 'bg-white shadow-sm text-indigo-600 font-semibold' : 'text-slate-500'}`}
              onClick={() => setIsSignup(true)}
            >
              Sign Up
            </button>
          </div>

          {error && <div className="mb-4 p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100">{error}</div>}

          {isSignup ? (
            <form onSubmit={handleSignup} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Full Name</label>
                <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition" placeholder="John Doe" />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Contact Number</label>
                <input type="tel" value={contact} onChange={(e) => setContact(e.target.value)} className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition" placeholder="e.g. 1234567890" />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition" placeholder="john@example.com" />
              </div>
              <button className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 rounded-lg shadow-md transition-colors">Create Account</button>
            </form>
          ) : (
            <form onSubmit={handleLogin} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email or Name</label>
                <input type="text" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition" placeholder="john@example.com" />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Login PIN (Last 6 digits of contact)</label>
                <input type="password" value={loginPin} onChange={(e) => setLoginPin(e.target.value)} className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition" placeholder="••••••" />
              </div>
              <button className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 rounded-lg shadow-md transition-colors">Sign In</button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

export default Login;

