}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isSignup, setIsSignup] = useState(false);
  const [name, setName] = useState('');
  const [contact, setContact] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loginIdentifier, setLoginIdentifier] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [error, setError] = useState('');

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !contact || !email || !password) {
      setError('Please fill all fields');
      return;
    }
    const newUser: User = { name, contact, email, password };
    const users = JSON.parse(localStorage.getItem('omnistock_users') || '[]');

    // Check if user already exists based on contact (simplified)
    if (users.some((u: User) => u.contact === contact)) {
      setError('A user with this contact already exists.');
      return;
    }

    users.push(newUser);
    localStorage.setItem('omnistock_users', JSON.stringify(users));
    setError('Account created! Login using the last 6 digits of your contact.');
    setIsSignup(false);
    // Reset fields
    setLoginIdentifier(contact.slice(-6));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users: User[] = JSON.parse(localStorage.getItem('omnistock_users') || '[]');
    const foundUser = users.find(u => {
      const contactPin = u.contact.slice(-6);
      return contactPin === loginIdentifier && u.password === loginPassword;
    });

    if (foundUser) {
      onLogin(foundUser);
    } else {
      setError('Invalid Last 6 Digits or Password');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100">
