// Detect if the app is running within the Android Studio WebView wrapper
const AndroidBridge = (window as any).AndroidBridge;

interface ReportsProps {
  inventory: StockItem[];
}

const Reports: React.FC<ReportsProps> = ({ inventory }) => {
  const [insight, setInsight] = useState<string>('Analyzing your data with AI...');
  const [loadingInsight, setLoadingInsight] = useState(false);

  useEffect(() => {
    const fetchInsight = async () => {
      if (inventory.length === 0) {
        setInsight("Add inventory to get smart insights.");
        return;
      }
      setLoadingInsight(true);
      const res = await generateInventoryInsight(inventory.slice(0, 10));
      setInsight(res || "Inventory levels look optimal.");
      setLoadingInsight(false);
    };
    fetchInsight();
  }, [inventory]);

  const categoryData = CATEGORIES.map(cat => ({
    name: cat,
    value: inventory.filter(i => i.category === cat).reduce((sum, i) => sum + i.quantity, 0),
    totalValue: inventory.filter(i => i.category === cat).reduce((sum, i) => sum + (i.price * i.quantity), 0)
  })).filter(d => d.value > 0);

  const totalValue = inventory.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalStock = inventory.reduce((sum, item) => sum + item.quantity, 0);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316', '#eab308', '#22c55e'];

  const handleExportPDF = () => {
    const reportSummary = `OmniStock Report: Total Stock ${totalStock}, Total Value $${totalValue.toFixed(2)}`;
    if (AndroidBridge) {
      AndroidBridge.shareReport(reportSummary, "PDF");
    } else {
      alert(`Generating PDF Report... (Simulated)\n${reportSummary}`);
    }
  };

  const handleExportExcel = () => {
    const reportSummary = `Inventory Export: ${inventory.length} items cataloged.`;
    if (AndroidBridge) {
      AndroidBridge.shareReport(reportSummary, "Excel");
    } else {
      alert(`Exporting to Excel... (Simulated)\n${reportSummary}`);
    }
  };

  const handleShare = () => {
    const shareText = `OmniStock Inventory Report\n---\nTotal Items: ${totalStock}\nTotal Value: $${totalValue.toFixed(2)}\nAI Insight: ${insight}`;
    if (AndroidBridge) {
      AndroidBridge.shareReport(shareText, "Summary");
    } else if (navigator.share) {
      navigator.share({ title: 'OmniStock Summary', text: shareText }).catch(() => {});
    } else {
      alert(shareText);
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
            <i className="fas fa-boxes-stacked text-xl"></i>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500">Total Items</p>
            <p className="text-2xl font-bold text-slate-800">{totalStock}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="w-12 h-12 bg-green-50 rounded-xl flex items-center justify-center text-green-600">
            <i className="fas fa-dollar-sign text-xl"></i>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500">Inventory Value</p>
            <p className="text-2xl font-bold text-slate-800">${totalValue.toLocaleString()}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="w-12 h-12 bg-violet-50 rounded-xl flex items-center justify-center text-violet-600">
            <i className="fas fa-tags text-xl"></i>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500">Categories</p>
            <p className="text-2xl font-bold text-slate-800">{categoryData.length}</p>
          </div>
        </div>
      </div>

      <div className="bg-indigo-900 text-white rounded-2xl p-6 shadow-xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10">
          <i className="fas fa-brain text-8xl"></i>
        </div>
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-4">
            <span className="flex h-2 w-2 relative">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-indigo-300"></span>
            </span>
            <h3 className="text-sm font-bold uppercase tracking-widest text-indigo-300">Smart AI Insight</h3>
          </div>
          <div className="text-lg font-medium leading-relaxed italic">
            {loadingInsight ? "Analyzing Inventory..." : insight}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <i className="fas fa-chart-pie text-indigo-500"></i>
            Stock Distribution
          </h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
              <i className="fas fa-chart-bar text-indigo-500"></i>
              Financial Summary
            </h3>
            <div className="flex gap-2">
              <button onClick={handleExportPDF} className="p-2 bg-slate-50 text-slate-600 rounded-lg hover:bg-slate-100 transition" title="Export PDF">
                <i className="fas fa-file-pdf"></i>
              </button>
              <button onClick={handleExportExcel} className="p-2 bg-slate-50 text-slate-600 rounded-lg hover:bg-slate-100 transition" title="Export Excel">
                <i className="fas fa-file-excel"></i>
              </button>
              <button onClick={handleShare} className="p-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 transition">
                <ShareIcon />
              </button>
            </div>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={categoryData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} />
                <Bar dataKey="totalValue" fill="#6366f1" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reports;
